        worksheetCount: 1,
        itemCount: 20,
        gridSize: 10,
        operationType: 'mixed',
        selectedOperations: ['add','sub'],
        numberRange: '1-20',
        allowCarry: true,
        allowBorrow: true,
        allowRemainder: false,
