    );
};

const tourSteps: TourStep[] = [
    { targetId: 'tour-logo', title: 'Hoş Geldiniz', content: 'Bursa Disleksi AI platformuna hoş geldiniz. Hızlı bir tura başlayalım mı?', position: 'bottom' },
    { targetId: 'tour-search', title: 'Etkinlik Arama', content: 'İstediğiniz etkinliği veya konuyu buradan hızla bulabilirsiniz.', position: 'bottom' },
    { targetId: 'tour-sidebar', title: 'Kategoriler', content: 'Sol menüden etkinlik kategorilerine ulaşabilirsiniz.', position: 'right' },
    { targetId: 'tour-workbook-btn', title: 'Çalışma Kitapçığı', content: 'Seçtiğiniz etkinlikleri buraya ekleyerek tek bir PDF kitapçık oluşturabilirsiniz.', position: 'bottom' },
    { targetId: 'tour-ocr-btn', title: 'Akıllı Tarayıcı (OCR)', content: 'Fiziksel kağıtları tarayıp dijitalleştirmek için bu ikonu kullanın.', position: 'right' },
    { targetId: 'tour-history-btn', title: 'Geçmiş', content: 'Daha önce oluşturduğunuz etkinliklere buradan ulaşabilirsiniz.', position: 'bottom' },
];

const AppContent: React.FC = () => {
    const { user, logout } = useAuth();
    const { activeStudent, setActiveStudent, students } = useStudent();
    const [currentView, setCurrentView] = useState<ExtendedView>('generator');
    const [viewHistory, setViewHistory] = useState<ExtendedView[]>([]); 

    const [selectedActivity, setSelectedActivity] = useState<ActivityType | null>(null);
    const [worksheetData, setWorksheetData] = useState<WorksheetData>(null);
    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [error, setError] = useState<string | null>(null);

    const [activeCurriculumSession, setActiveCurriculumSession] = useState<ActiveCurriculumSession | null>(null);
    const [loadedCurriculum, setLoadedCurriculum] = useState<Curriculum | null>(null);

    const [isSidebarOpen, setIsSidebarOpen] = useState(false);
    const [isSidebarExpanded, setIsSidebarExpanded] = useState(true);

    const [zenMode, setZenMode] = useState(false);

    const [openModal, setOpenModal] = useState<ModalType | null>(null);
    const [isFeedbackOpen, setIsFeedbackOpen] = useState(false);
    const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);
    const [unreadCount, setUnreadCount] = useState(0);
    const [isTourOpen, setIsTourOpen] = useState(false);

    const [studentProfile, setStudentProfile] = useState<StudentProfile | null>(null);
    const [isStudentModalOpen, setIsStudentModalOpen] = useState(false);
    const [selectedSavedReport, setSelectedSavedReport] = useState<SavedAssessment | null>(null);

    const [workbookItems, setWorkbookItems] = useState<CollectionItem[]>([]);
    const [workbookSettings, setWorkbookSettings] = useState<WorkbookSettings>({
        title: 'Çalışma Kitapçığı',
        studentName: '',
        schoolName: '',
        year: new Date().getFullYear().toString(),
        teacherNote: '',
        theme: 'modern',
        accentColor: '#4f46e5',
        coverStyle: 'centered',
        showTOC: true,
        showPageNumbers: true,
        showWatermark: false,
        watermarkOpacity: 0.05,
        showBackCover: true
    });

    const [theme, setTheme] = useState<AppTheme>(() => {
        try {
            const storedTheme = localStorage.getItem('app-theme');
            return (storedTheme as AppTheme) || 'anthracite';
        } catch (e) {
            return 'anthracite';
        }
    });

    const [uiSettings, setUiSettings] = useState<UiSettings>(() => {
        try {
            const stored = localStorage.getItem('app-ui-settings');
            return stored ? { ...initialUiSettings, ...JSON.parse(stored) } : initialUiSettings;
        } catch (e) {
            return initialUiSettings;
        }
    });

    const [styleSettings, setStyleSettings] = useState<StyleSettings>(initialStyleSettings);

    const [historyItems, setHistoryItems] = useState<HistoryItem[]>(() => {
        try {
            const stored = localStorage.getItem('user_history');
            return stored ? JSON.parse(stored) : [];
        } catch { return []; }
    });

    // --- AUTOMATIC SIDEBAR FLOW ---

    // Expand sidebar when an activity is selected (ready for config)
    useEffect(() => {
        if (selectedActivity && !worksheetData) {
            setIsSidebarExpanded(true);
        }
    }, [selectedActivity]);

    // Collapse sidebar when worksheet data is received (maximize workspace)
    useEffect(() => {
        if (worksheetData && worksheetData.length > 0) {
            setIsSidebarExpanded(false);
        }
    }, [worksheetData]);

    const navigateTo = (view: ExtendedView) => {
        if (currentView === view) return;
        setViewHistory(prev => [...prev, currentView]);
        setCurrentView(view);
    };

    const handleGoBack = () => {
        if (currentView === 'generator' && activeCurriculumSession) {
            setActiveCurriculumSession(null);
            navigateTo('curriculum');
            return;
        }

        if (viewHistory.length > 0) {
            const newHistory = [...viewHistory];
            const prevView = newHistory.pop();
            setViewHistory(newHistory);
            if (prevView) setCurrentView(prevView);
        } else {
            setCurrentView('generator');
        }
    };

    useEffect(() => {
        localStorage.setItem('user_history', JSON.stringify(historyItems));
    }, [historyItems]);

    const addToHistory = (activityType: ActivityType, data: SingleWorksheetData[]) => {
        const activity = ACTIVITIES.find(a => a.id === activityType);
        const category = ACTIVITY_CATEGORIES.find(c => c.activities.includes(activityType));
        if (!activity || !category) return;

        const newItem: HistoryItem = {
            id: Date.now().toString() + Math.random(),
            userId: user?.id || 'guest',
            activityType,
            data,
            timestamp: new Date().toISOString(),
            title: activity.title,
            category: { id: category.id, title: category.title }
        };

        setHistoryItems(prev => [newItem, ...prev].slice(0, 100));
    };

    const clearHistory = () => { setHistoryItems([]); };
    const deleteHistoryItem = (id: string) => { setHistoryItems(prev => prev.filter(i => i.id !== id)); };

    const handleRestoreFromHistory = (item: HistoryItem) => {
        loadSavedWorksheet({
            id: item.id, userId: item.userId, name: item.title, activityType: item.activityType,
            worksheetData: item.data, createdAt: item.timestamp,
            icon: ACTIVITIES.find(a => a.id === item.activityType)?.icon || 'fa-file',
            category: item.category
        });
        setOpenModal(null);
    };

    const handleSaveHistoryItem = (item: HistoryItem) => {
        if (!user) { setIsAuthModalOpen(true); return; }
        addSavedWorksheet(`${item.title} (Geçmiş)`, item.activityType, item.data);
    };

    const addSavedWorksheet = async (name: string, activityType: ActivityType, data: SingleWorksheetData[]) => {
        if (!user) { setIsAuthModalOpen(true); return; }
        const activity = ACTIVITIES.find(a => a.id === activityType);
        const category = ACTIVITY_CATEGORIES.find(c => c.activities.includes(activityType));
        if (!activity || !category) return;

        try {
            await worksheetService.saveWorksheet(
                user.id, name, activityType, data, activity.icon,
                { id: category.id, title: category.title }, styleSettings, studentProfile || undefined, studentProfile?.studentId
            );
            alert(`Etkinlik "${name}" adıyla arşivinize kaydedildi.`);
        } catch (e: any) {
            console.error("Save error:", e);
            alert(`Kaydedilirken bir hata oluştu: ${e.message}.`);
        }
    };

    const loadSavedWorksheet = (item: any) => {
        if (item.report || item.activityType === ActivityType.ASSESSMENT_REPORT) {
            setSelectedSavedReport(item as SavedAssessment);
            return;
        }
        if (item.schedule && item.durationDays) {
            setLoadedCurriculum(item as Curriculum);
            navigateTo('curriculum');
            return;
        }
        if (item.activityType === ActivityType.WORKBOOK || item.workbookItems) {
            if (item.workbookItems && item.workbookSettings) {
                setWorkbookItems(item.workbookItems);
                setWorkbookSettings(item.workbookItems);
                navigateTo('workbook');
            }
            return;
        }
        setSelectedActivity(item.activityType);
        setWorksheetData(item.worksheetData);
        if (item.styleSettings) setStyleSettings(item.styleSettings);
        if (item.studentProfile) {
            setStudentProfile(item.studentProfile);
            if (item.studentId) {
                const s = students.find(x => x.id === item.studentId);
                if (s) setActiveStudent(s);
            }
        } else {
            setStudentProfile(null);
            setActiveStudent(null);
        }
        navigateTo('generator');
    };

    const handleSelectActivity = (activityType: ActivityType | null) => {
        if (currentView !== 'generator') {
             navigateTo('generator');
        }
        setActiveCurriculumSession(null);
        setSelectedActivity(activityType);
        setWorksheetData(null);
        setError(null);
        setCurrentView('generator');
        if (isSidebarOpen) setIsSidebarOpen(false);
        // Ensure sidebar is expanded to show generator options
        if (activityType) {
            setIsSidebarExpanded(true);
        }
    };

    const handleStartCurriculumActivity = (planId: string, day: number, activityId: string, activityType: string, studentName: string, title: string, studentId?: string) => {
        setActiveCurriculumSession({ planId, day, activityId, studentName, activityTitle: title, studentId });
        if (studentId) {
            const s = students.find(x => x.id === studentId);
            if (s) setActiveStudent(s);
        } else {
            setStudentProfile({ name: studentName, school: '', grade: '', date: new Date().toLocaleDateString('tr-TR') });
        }
        setSelectedActivity(activityType as ActivityType);
        setWorksheetData(null); 
        navigateTo('generator');
    };

    const handleCompleteCurriculumActivity = async () => {
        if (!activeCurriculumSession || !user) return;
        setIsLoading(true);
        try {
            if (worksheetData) {
                 await addSavedWorksheet(`${activeCurriculumSession.studentName} - ${activeCurriculumSession.activityTitle}`, selectedActivity!, worksheetData);
            }
            await curriculumService.updateActivityStatus(activeCurriculumSession.planId, activeCurriculumSession.day, activeCurriculumSession.activityId, 'completed');
            setActiveCurriculumSession(null);
            navigateTo('curriculum');
            alert("Harika! Aktivite tamamlandı ve plana işlendi.");
        } catch (e) {
            alert("Bir hata oluştu.");
        } finally {
            setIsLoading(false);
        }
    };

    const handleAddToWorkbookGeneral = (activityType: ActivityType, data: any) => {
        if (activityType && data) {
            const dataArray = Array.isArray(data) ? data : [data];
            const newItems: CollectionItem[] = dataArray.map((sheet: any) => ({
                id: crypto.randomUUID(),
                activityType: activityType,
                data: sheet,
                settings: { ...styleSettings },
                title: sheet.title || ACTIVITIES.find(a => a.id === activityType)?.title || 'Etkinlik'
            }));
            setWorkbookItems(prev => [...prev, ...newItems]);
            alert("Kitapçığa eklendi!");
        }
    };

    const handleAddToWorkbook = () => {
        if (selectedActivity && worksheetData) {
            handleAddToWorkbookGeneral(selectedActivity, worksheetData);
        }
    };

    const handleAutoGenerateWorkbook = async (report: AssessmentReport) => {
        setIsLoading(true);
        navigateTo('workbook'); 
        const newItems: CollectionItem[] = [];
        const defaultOptions: GeneratorOptions = { mode: 'fast', difficulty: 'Orta', worksheetCount: 1, itemCount: 10 };
        try {
            const reportItem: CollectionItem = {
                id: crypto.randomUUID(),
                activityType: ActivityType.ASSESSMENT_REPORT,
                data: { id: 'temp-report', userId: user?.id || 'guest', studentName: studentProfile?.name || 'Öğrenci', createdAt: new Date().toISOString(), report: report } as any, 
                settings: { ...styleSettings, showStudentInfo: false, showFooter: false },
                title: `Rapor: ${studentProfile?.name || 'Öğrenci'}`
            };
            newItems.push(reportItem);
            for (const roadItem of report.roadmap) {
                const activityId = roadItem.activityId as ActivityType;
                const pascalName = toPascalCase(activityId);
                const generatorName = `generateOffline${pascalName}`;
                const generator = (offlineGenerators as any)[generatorName];
                if (generator) {
                    try {
                        const generatedData = await generator(defaultOptions);
                        generatedData.forEach((sheet: any) => {
                            newItems.push({
                                id: crypto.randomUUID(), activityType: activityId, data: sheet,
                                settings: { ...styleSettings },
                                title: ACTIVITIES.find(a => a.id === activityId)?.title || activityId
                            });
                        });
                    } catch (genErr) { }
                }
            }
            setWorkbookItems(newItems);
            setWorkbookSettings(prev => ({ ...prev, title: `Kişisel Gelişim Planı`, studentName: studentProfile?.name || '' }));
        } catch (e) {
            alert("Otomatik kitapçık oluşturulurken bir hata meydana geldi.");
        } finally {
            setIsLoading(false);
        }
    };

    const handleAddToWorkbookFromReport = (assessment: SavedAssessment) => {
        const newItem: CollectionItem = {
            id: crypto.randomUUID(),
            activityType: ActivityType.ASSESSMENT_REPORT, 
            data: assessment, 
            settings: { ...styleSettings, showStudentInfo: false, showFooter: false },
            title: `Rapor: ${assessment.studentName}`
        };
        setWorkbookItems(prev => [...prev, newItem]);
    };

    const handleOCRResult = (result: any) => {
        alert("İçerik başarıyla tarandı!");
        navigateTo('generator');
    };

    const AssessmentModule = lazy(() => import('./components/AssessmentModule').then(module => ({ default: module.AssessmentModule })));

    if (currentView === 'admin') return <Suspense fallback={<LoadingSpinner />}><AdminDashboard onBack={handleGoBack} /></Suspense>;
    if (currentView === 'profile') return <Suspense fallback={<LoadingSpinner />}><ProfileView onBack={handleGoBack} onSelectActivity={handleSelectActivity} onLoadSaved={loadSavedWorksheet} /></Suspense>;
    if (currentView === 'messages') return <Suspense fallback={<LoadingSpinner />}><MessagesView onBack={handleGoBack} onRefreshNotifications={() => {}} /></Suspense>;
    if (currentView === 'ocr') return <Suspense fallback={<LoadingSpinner />}><OCRScanner onBack={handleGoBack} onResult={handleOCRResult} /></Suspense>;
    if (currentView === 'students') return <Suspense fallback={<LoadingSpinner />}><StudentDashboard onBack={handleGoBack} onLoadMaterial={loadSavedWorksheet} /></Suspense>;

    if (currentView === 'reading-studio') return (
        <Suspense fallback={<LoadingSpinner />}>
            <ReadingStudio onBack={handleGoBack} onAddToWorkbook={(data: any) => handleAddToWorkbookGeneral('STORY_COMPREHENSION', data)} />
        </Suspense>
    );

    if (currentView === 'math-studio') return (
        <Suspense fallback={<LoadingSpinner />}>
            <MathStudio onBack={handleGoBack} onAddToWorkbook={(data: any) => handleAddToWorkbookGeneral('MATH_STUDIO' as any, data)} />
        </Suspense>
    );

    if (currentView === 'curriculum') return (
        <Suspense fallback={<LoadingSpinner />}>
            <CurriculumView onBack={handleGoBack} onSelectActivity={handleSelectActivity} onStartCurriculumActivity={handleStartCurriculumActivity} initialPlan={loadedCurriculum} />
        </Suspense>
    );

    const headerIconBtnClass = "p-2 text-[var(--text-secondary)] hover:text-[var(--accent-color)] hover:drop-shadow-[0_0_5px_rgba(251,191,36,0.5)] transition-all duration-300 rounded-md";

    return (
        <div className="flex flex-col h-screen bg-transparent font-sans transition-colors duration-300">
            <header className={`relative bg-[var(--panel-bg)] backdrop-blur-sm border-b border-[var(--border-color)] shadow-sm z-10 transition-all duration-500 ${zenMode ? '-mt-20 opacity-0 pointer-events-none' : 'mt-0 opacity-100'}`}>
                <div className="w-full px-4 sm:px-6 py-3 flex justify-between items-center">
                    <div className="flex items-center">
                        <button onClick={() => setIsSidebarOpen(true)} className="md:hidden text-[var(--text-muted)] mr-3 p-2 hover:text-[var(--text-primary)] transition-colors"><i className="fa-solid fa-bars fa-lg"></i></button>
                        <button id="tour-logo" onClick={() => { navigateTo('generator'); setSelectedActivity(null); setWorksheetData(null); setActiveCurriculumSession(null); }} className="flex items-center gap-3 px-2 py-1 rounded-lg relative z-50">
                            <DyslexiaLogo className="h-10 w-auto" />
                        </button>
                    </div>

                    <div className="flex items-center gap-2">
                        <GlobalSearch onSelectActivity={handleSelectActivity} />

                        <div className="flex items-center gap-1 border-r border-[var(--border-color)] pr-2 mx-1">
                            <button onClick={() => setIsTourOpen(true)} className={headerIconBtnClass} title="Nasıl Kullanılır?"><i className="fa-solid fa-question-circle fa-lg"></i></button>
                            <button onClick={() => setOpenModal('developer')} className={headerIconBtnClass} title="Geliştirici İletişim"><i className="fa-solid fa-laptop-code fa-lg"></i></button>
                            <button onClick={() => setOpenModal('about')} className={headerIconBtnClass} title="Hakkımızda"><i className="fa-solid fa-circle-info fa-lg"></i></button>
                            <button onClick={() => setIsFeedbackOpen(true)} className={headerIconBtnClass} title="İletişim / Hata Bildir"><i className="fa-solid fa-headset fa-lg"></i></button>
                        </div>

                        <button onClick={() => navigateTo('assessment')} className="hidden sm:flex items-center gap-2 px-4 py-2 bg-[var(--accent-color)] text-black rounded-full text-xs font-extrabold shadow-md hover:scale-105 transition-all border border-[var(--accent-hover)]" title="Öğrenme Güçlüğü Analizi"><i className="fa-solid fa-user-doctor"></i> Değerlendirme</button>

                        <div className="h-6 w-px bg-[var(--border-color)] mx-1 hidden sm:block"></div>

                        <div className="flex items-center gap-2">
                            <button id="tour-workbook-btn" onClick={() => navigateTo('workbook')} className="relative p-2 text-[var(--text-secondary)] hover:text-emerald-500 transition-all rounded-md group" title="Çalışma Kitapçığı">
                                <i className="fa-solid fa-book-open-reader fa-lg"></i>
                                {workbookItems.length > 0 && <span className="absolute -top-1 -right-1 bg-emerald-500 text-white text-[10px] font-bold px-1.5 rounded-full border border-black min-w-[18px] text-center">{workbookItems.length}</span>}
                            </button>
                            <button id="tour-favorites-btn" onClick={() => navigateTo('favorites')} className="p-2 text-[var(--text-secondary)] hover:text-red-500 transition-all rounded-md relative group" title="Favoriler"><i className="fa-solid fa-heart fa-lg"></i></button>

                            {user ? (
                                <>
                                    {user.role === 'admin' && <button onClick={() => navigateTo('admin')} className="p-2 text-purple-400 hover:bg-purple-900/20 rounded-md transition-all" title="Yönetici Paneli"><i className="fa-solid fa-shield-halved fa-lg"></i></button>}
                                    <button id="tour-messages-btn" onClick={() => navigateTo('messages')} className={headerIconBtnClass + " relative"} title="Mesajlar"><i className="fa-solid fa-envelope fa-lg"></i>{unreadCount > 0 && <span className="absolute top-0 right-0 bg-red-500 text-white text-[10px] font-bold px-1.5 rounded-full border-2 border-black">{unreadCount}</span>}</button>
                                    <button id="tour-shared-btn" onClick={() => navigateTo('shared')} className={headerIconBtnClass} title="Paylaşılanlar"><i className="fa-solid fa-share-nodes fa-lg"></i></button>
                                    <button id="tour-archive-btn" onClick={() => navigateTo('savedList')} className={headerIconBtnClass} title="Arşiv"><i className="fa-solid fa-box-archive fa-lg"></i></button>
                                    <button id="tour-history-btn" onClick={() => setOpenModal('history')} className={headerIconBtnClass} title="Geçmiş"><i className="fa-solid fa-clock-rotate-left fa-lg"></i></button>
                                    <button id="tour-profile-btn" onClick={() => navigateTo('profile')} className="ml-2"><img src={user.avatar} alt={user.name} className="w-9 h-9 rounded-full border-2 border-[var(--border-color)] shadow-sm hover:border-[var(--accent-color)] transition-colors bg-zinc-800" /></button>
                                </>
                            ) : (
                                <button onClick={() => setIsAuthModalOpen(true)} className="ml-2 px-5 py-2 bg-[var(--bg-paper)] text-[var(--text-primary)] border border-[var(--border-color)] rounded-lg font-black text-sm hover:bg-[var(--bg-inset)] transition-all">Giriş Yap</button>
                            )}
                        </div>
                        <div className="h-6 w-px bg-[var(--border-color)] mx-1"></div>
                        <button onClick={() => setOpenModal('settings')} className={headerIconBtnClass}><i className="fa-solid fa-gear fa-lg"></i></button>
                    </div>
                </div>
            </header>

            <div className="flex flex-1 overflow-hidden">
                {isSidebarOpen && <div className="fixed inset-0 bg-black/50 z-20 md:hidden" onClick={() => setIsSidebarOpen(false)}></div>}

                <div 
                    onMouseEnter={() => !selectedActivity && setIsSidebarExpanded(true)} 
                    className={`transition-all duration-500 ease-in-out h-full ${zenMode ? '-ml-80 w-0 opacity-0 overflow-hidden' : ''}`}
                >
                    <Sidebar
                        isSidebarOpen={isSidebarOpen}
                        closeSidebar={() => setIsSidebarOpen(false)}
                        selectedActivity={selectedActivity}
                        onSelectActivity={handleSelectActivity}
                        setWorksheetData={setWorksheetData}
                        setIsLoading={setIsLoading}
                        setError={setError}
                        isLoading={isLoading}
                        onAddToHistory={addToHistory}
                        isExpanded={isSidebarExpanded}
                        onOpenStudentModal={() => navigateTo('students')}
                        studentProfile={studentProfile}
                        styleSettings={styleSettings}
                        onOpenOCR={() => navigateTo('ocr')}
                        onOpenCurriculum={() => navigateTo('curriculum')}
                        onOpenReadingStudio={() => navigateTo('reading-studio')}
                        onOpenMathStudio={() => navigateTo('math-studio')}
                    />
                </div>

                <div 
                    className="flex-1 flex flex-col overflow-hidden" 
                    onMouseEnter={() => !selectedActivity && setIsSidebarExpanded(false)}
                >
                    <ContentArea
                        currentView={currentView as View}
                        onBackToGenerator={() => { 
                            if(currentView !== 'generator') handleGoBack();
                            else { setSelectedActivity(null); setWorksheetData(null); setActiveCurriculumSession(null); }
                        }}
                        activityType={selectedActivity}
                        worksheetData={worksheetData}
                        isLoading={isLoading}
                        error={error}
                        styleSettings={styleSettings}
                        onStyleChange={setStyleSettings}
                        onSave={addSavedWorksheet}
                        onLoadSaved={loadSavedWorksheet}
                        onFeedback={() => setIsFeedbackOpen(true)}
                        onOpenAuth={() => setIsAuthModalOpen(true)}
                        onSelectActivity={handleSelectActivity}
                        workbookItems={workbookItems}
                        setWorkbookItems={setWorkbookItems}
                        workbookSettings={workbookSettings}
                        setWorkbookSettings={setWorkbookSettings}
                        onAddToWorkbook={handleAddToWorkbook}
                        onAutoGenerateWorkbook={handleAutoGenerateWorkbook}
                        studentProfile={studentProfile}
                        zenMode={zenMode}
                        toggleZenMode={() => setZenMode(!zenMode)}
                        activeCurriculumSession={activeCurriculumSession}
                        onCompleteCurriculumActivity={handleCompleteCurriculumActivity}
                    />

                    {currentView === 'assessment' && (
                        <div className="absolute inset-0 bg-white dark:bg-zinc-900 z-40 overflow-y-auto">
                            <Suspense fallback={<LoadingSpinner />}>
                                <AssessmentModule onBack={handleGoBack} onSelectActivity={handleSelectActivity} onAddToWorkbook={handleAddToWorkbookFromReport} onAutoGenerateWorkbook={handleAutoGenerateWorkbook} />
                            </Suspense>
                        </div>
                    )}
                </div>
            </div>

            <TourGuide steps={tourSteps} isOpen={isTourOpen} onClose={() => setIsTourOpen(false)} />
            <FeedbackModal isOpen={isFeedbackOpen} onClose={() => setIsFeedbackOpen(false)} activityType={selectedActivity} activityTitle={selectedActivity ? ACTIVITIES.find(a => a.id === selectedActivity)?.title : undefined} />
            <AuthModal isOpen={isAuthModalOpen} onClose={() => setIsAuthModalOpen(false)} />
            <StudentInfoModal isOpen={isStudentModalOpen} onClose={() => setIsStudentModalOpen(false)} currentProfile={studentProfile} onSave={(p) => setStudentProfile(p)} onClear={() => setStudentProfile(null)} />
            <SettingsModal isOpen={openModal === 'settings'} onClose={() => setOpenModal(null)} uiSettings={uiSettings} onUpdateUiSettings={setUiSettings} theme={theme} onUpdateTheme={setTheme} />
            <AssessmentReportViewer assessment={selectedSavedReport} onClose={() => setSelectedSavedReport(null)} user={user} onSelectActivity={handleSelectActivity} />
            <Modal isOpen={openModal === 'history'} onClose={() => setOpenModal(null)} title="İşlem Geçmişi">
                <HistoryView historyItems={historyItems} onRestore={handleRestoreFromHistory} onSaveToArchive={handleSaveHistoryItem} onDelete={deleteHistoryItem} onClearAll={clearHistory} onClose={() => setOpenModal(null)} />
            </Modal>
             <Modal isOpen={openModal === 'about'} onClose={() => setOpenModal(null)} title="Hakkımızda">
                <div className="text-center space-y-6">
                    <DyslexiaLogo className="h-16 w-auto mx-auto" />
                    <div className="space-y-4 text-zinc-600 dark:text-zinc-300">
                        <p className="leading-relaxed">Bursa Disleksi AI, özel öğrenme güçlüğü yaşayan bireylerin eğitim süreçlerini desteklemek amacıyla geliştirilmiş bir yapay zeka platformudur.</p>
                    </div>
                </div>
            </Modal>
        </div>
    );
};

export const App: React.FC = () => {
  return (
    <AuthProvider>
        <StudentProvider>
          <AppContent />
        </StudentProvider>
    </AuthProvider>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { ActivityType, WorksheetData, Activity, GeneratorOptions, ActivityCategory } from '../types';
import { ACTIVITY_CATEGORIES, ACTIVITIES } from '../constants';
import * as generators from '../services/generators';
import * as offlineGenerators from '../services/offlineGenerators';
import { GeneratorView } from './GeneratorView';
import { statsService } from '../services/statsService';
import { adminService } from '../services/adminService';

interface SidebarProps {
  selectedActivity: ActivityType | null;
  onSelectActivity: (id: ActivityType | null) => void;
  setWorksheetData: (data: WorksheetData) => void;
  setIsLoading: (loading: boolean) => void;
  setError: (error: string | null) => void;
  isLoading: boolean;
  isSidebarOpen: boolean;
  closeSidebar: () => void;
  onAddToHistory: (activityType: ActivityType, data: WorksheetData) => void;
  isExpanded?: boolean;
  onOpenStudentModal?: () => void;
  studentProfile?: any;
  styleSettings?: any;
  onOpenOCR?: () => void;
  onOpenCurriculum?: () => void;
  onOpenReadingStudio?: () => void;
  onOpenMathStudio?: () => void;
}

const toPascalCase = (str: string): string => {
    return str.toLowerCase().split('_').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join('');
};

const Sidebar: React.FC<SidebarProps> = ({
  isSidebarOpen,
  closeSidebar,
  selectedActivity,
  onSelectActivity,
  setWorksheetData,
  setIsLoading,
  setError,
  isLoading,
  onAddToHistory,
  isExpanded = true,
  onOpenStudentModal,
  studentProfile,
  styleSettings,
  onOpenOCR,
  onOpenCurriculum,
  onOpenReadingStudio,
  onOpenMathStudio
}) => {
  const [openCategoryId, setOpenCategoryId] = useState<string | null>(null);
  const [allActivities, setAllActivities] = useState<Activity[]>(ACTIVITIES);

  useEffect(() => {
      const loadCustomActivities = async () => {
          try {
              const customActs = await adminService.getAllActivities();
              if (customActs && Array.isArray(customActs)) {
                  const mergedActivities = [...ACTIVITIES];
                  customActs.forEach(ca => {
                      if (!ca || !ca.id) return;
                      const index = mergedActivities.findIndex(a => a && a.id === ca.id);
                      if (index !== -1) mergedActivities[index] = { ...mergedActivities[index], ...ca };
                      else mergedActivities.push(ca);
                  });
                  setAllActivities(mergedActivities);
              }
          } catch (e) { console.error("Sidebar load error", e); }
      };
      loadCustomActivities();
  }, []);

  const getActivityById = (id: ActivityType | null): Activity | undefined => {
      if (!id) return undefined;
      return allActivities.find(a => a && a.id === id);
  }

  const handleGenerate = async (options: GeneratorOptions) => {
    if (!selectedActivity) return;
    setIsLoading(true);
    setWorksheetData(null);
    setError(null);
    const currentAct = getActivityById(selectedActivity);
    const promptId = currentAct?.promptId;
    try {
        let result: WorksheetData | null = null;
        if (promptId) {
             const promptTemplate = await adminService.getPromptTemplate(promptId);
             if (promptTemplate) {
                 const vars = { worksheetCount: options.worksheetCount, difficulty: options.difficulty, topic: options.topic || 'Genel', itemCount: options.itemCount };
                 const aiResult = await adminService.testPrompt(promptTemplate, vars);
                 if (Array.isArray(aiResult)) result = aiResult;
                 else if (aiResult && (aiResult as any).data && Array.isArray((aiResult as any).data)) result = (aiResult as any).data;
                 else result = [aiResult];
             }
        } 
        if (!result) {
            const pascalCaseName = toPascalCase(selectedActivity);
            const generatorFunctionName = `generate${pascalCaseName}FromAI`;
            const offlineGeneratorFunctionName = `generateOffline${pascalCaseName}`;
            const runOfflineGenerator = async () => {
                 const offlineGenerator = (offlineGenerators as any)[offlineGeneratorFunctionName];
                 if (offlineGenerator) return await offlineGenerator(options);
                 throw new Error(`"${currentAct?.title}" motoru bulunamadı.`);
            };
            if (options.mode === 'ai') {
                const onlineGenerator = (generators as any)[generatorFunctionName];
                if (onlineGenerator) {
                    try { result = await onlineGenerator(options); } 
                    catch (err) { result = await runOfflineGenerator(); }
                } else result = await runOfflineGenerator();
            } else result = await runOfflineGenerator();
        }
        if (result) {
            const labeledResult = result.map((page: any) => ({ ...page, title: page.title || currentAct?.title || 'Etkinlik' }));
            setWorksheetData(labeledResult);
            onAddToHistory(selectedActivity, labeledResult);
            statsService.incrementUsage(selectedActivity).catch(console.error);
        }
    } catch (e: any) { setError(e.message || "Hata oluştu."); } finally { setIsLoading(false); }
  };

  const categorizedActivities = useMemo(() => {
      return ACTIVITY_CATEGORIES.map(category => ({ 
          ...category, 
          items: allActivities.filter(act => act && act.id && category.activities.includes(act.id)) 
      })).filter(c => c.items.length > 0);
  }, [allActivities]);

  const currentActivityObj = selectedActivity ? getActivityById(selectedActivity) : undefined;

  return (
    <aside id="tour-sidebar" className={`fixed inset-y-0 left-0 z-30 bg-white/95 dark:bg-zinc-900/95 backdrop-blur-xl border-r border-zinc-200 dark:border-zinc-800 transition-all duration-500 flex flex-col h-full md:relative md:translate-x-0 ${isSidebarOpen ? 'translate-x-0 shadow-2xl' : '-translate-x-full md:shadow-none'} ${isExpanded ? 'w-[300px]' : 'w-[70px]'}`} aria-label="Etkinlik Menüsü">
        <div className="flex h-full flex-col">
            {selectedActivity && currentActivityObj ? (
                <GeneratorView activity={currentActivityObj} onGenerate={handleGenerate} onBack={() => onSelectActivity(null)} isLoading={isLoading} isExpanded={isExpanded} onOpenStudentModal={onOpenStudentModal} studentProfile={studentProfile} />
            ) : (
                <>
                <div className="flex-shrink-0 h-[56px] flex items-center justify-between px-3 border-b border-zinc-200/50 dark:border-zinc-800/50 bg-zinc-50/30 dark:bg-zinc-800/30">
                    {isExpanded ? (
                        <div className="relative w-full group">
                            <i className="fa-solid fa-search absolute left-3 top-1/2 -translate-y-1/2 text-zinc-400 group-focus-within:text-indigo-500 transition-colors text-[10px]"></i>
                            <input type="text" placeholder="Etkinlik ara..." className="w-full h-8 pl-8 pr-2 bg-white dark:bg-black/20 border border-zinc-200 dark:border-zinc-700 rounded-lg text-[11px] font-semibold text-zinc-700 dark:text-zinc-200 placeholder-zinc-400 outline-none focus:border-indigo-500/50 focus:ring-2 focus:ring-indigo-500/10 transition-all shadow-sm"/>
                        </div>
                    ) : (
                        <div className="w-full flex justify-center"><div className="w-8 h-8 bg-indigo-500/10 text-indigo-600 dark:text-indigo-400 rounded-lg flex items-center justify-center"><i className="fa-solid fa-layer-group text-sm"></i></div></div>
                    )}
                    <button onClick={closeSidebar} className="md:hidden ml-2 w-7 h-7 flex items-center justify-center rounded-full hover:bg-zinc-100 dark:hover:bg-zinc-700 text-zinc-500 transition-colors"><i className="fa-solid fa-xmark text-sm"></i></button>
                </div>

                {isExpanded && (
                    <div className="px-4 py-4 grid grid-cols-1 gap-2 shrink-0 border-b border-dashed border-zinc-200 dark:border-zinc-800/50 mb-2">
                        <button onClick={onOpenStudentModal} className="group w-full relative overflow-hidden bg-indigo-600 hover:bg-indigo-700 p-3 rounded-2xl transition-all flex items-center gap-4 shadow-lg shadow-indigo-500/20">
                            <div className="w-10 h-10 shrink-0 rounded-xl bg-white/20 flex items-center justify-center text-white shadow-sm group-hover:scale-110 transition-transform">
                                <i className="fa-solid fa-user-graduate text-lg"></i>
                            </div>
                            <div className="flex flex-col items-start">
                                <span className="text-[11px] font-black text-white uppercase tracking-widest leading-none">Öğrencilerim</span>
                                <span className="text-[9px] text-indigo-100 mt-1">Yönetim Paneli</span>
                            </div>
                            <i className="fa-solid fa-chevron-right text-indigo-300 ml-auto text-[10px]"></i>
                        </button>

                        <div className="grid grid-cols-2 gap-2 mt-1">
                            <button onClick={onOpenOCR} className="p-3 rounded-2xl bg-zinc-50 dark:bg-zinc-800 border border-zinc-200 dark:border-zinc-700 hover:border-indigo-300 transition-all flex flex-col items-center gap-1 group">
                                <i className="fa-solid fa-camera text-zinc-400 group-hover:text-indigo-500 transition-colors"></i>
                                <span className="text-[9px] font-bold text-zinc-500 dark:text-zinc-400 uppercase">Tarayıcı</span>
                            </button>
                            <button onClick={onOpenCurriculum} className="p-3 rounded-2xl bg-zinc-50 dark:bg-zinc-800 border border-zinc-200 dark:border-zinc-700 hover:border-emerald-300 transition-all flex flex-col items-center gap-1 group">
                                <i className="fa-solid fa-calendar-check text-zinc-400 group-hover:text-emerald-500 transition-colors"></i>
                                <span className="text-[9px] font-bold text-zinc-500 dark:text-zinc-400 uppercase">Planlama</span>
                            </button>
                        </div>
                    </div>
                )}

                <nav className="flex-1 overflow-y-auto px-2 py-1 custom-scrollbar min-h-0 space-y-0.5">
                    {categorizedActivities.map((category) => {
                        const isOpen = openCategoryId === category.id;
                        return (
                            <div key={category.id}>
                                <button onClick={() => isExpanded && setOpenCategoryId(isOpen ? null : category.id)} className={`w-full flex items-center gap-2 px-2 py-1.5 rounded-lg transition-all duration-200 group ${!isExpanded ? 'justify-center' : ''} ${isOpen && isExpanded ? 'bg-zinc-800 text-white dark:bg-white dark:text-zinc-900' : 'hover:bg-zinc-100 dark:hover:bg-zinc-800 text-zinc-600 dark:text-zinc-400'}`} title={!isExpanded ? category.title : undefined}>
                                    <div className={`w-5 h-5 rounded-md flex items-center justify-center text-[10px] transition-all shrink-0 ${isOpen && isExpanded ? 'text-white dark:text-black' : 'text-zinc-500 dark:text-zinc-500'}`}><i className={category.icon}></i></div>
                                    {isExpanded && <><span className="flex-1 text-left text-[11px] font-bold uppercase tracking-tight truncate">{category.title}</span><i className={`fa-solid fa-chevron-down text-[8px] opacity-50 transition-transform duration-200 ${isOpen ? 'rotate-180' : ''}`}></i></>}
                                </button>
                                {isExpanded && isOpen && (
                                    <div className="overflow-hidden animate-in slide-in-from-left-1 duration-200">
                                        <div className="pl-3 ml-[11px] border-l border-zinc-200 dark:border-zinc-800 mt-0.5 space-y-0.5">
                                            {category.items.map(activity => (
                                                <button key={activity.id} onClick={() => onSelectActivity(activity.id)} className={`w-full text-left px-3 py-1 rounded-md text-[10px] font-medium transition-all flex items-center gap-1.5 relative ${selectedActivity === activity.id ? 'bg-indigo-50/50 dark:bg-indigo-900/10 text-indigo-700 dark:text-indigo-300 font-bold' : 'text-zinc-500 dark:text-zinc-400 hover:text-zinc-900 dark:hover:text-zinc-100 hover:bg-zinc-50 dark:hover:bg-zinc-800/30'}`}>
                                                    <span className={`w-1 h-1 rounded-full ${selectedActivity === activity.id ? 'bg-indigo-500' : 'bg-transparent border border-zinc-300'}`}></span>
                                                    <span className="truncate">{activity.title}</span>
                                                </button>
                                            ))}
                                        </div>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </nav>
                </>
            )}
        </div>
    </aside>
  );
};

export default Sidebar;
